(window.webpackJsonp=window.webpackJsonp||[]).push([[282],{909:function(n,t){n.exports='\x3c!-- \ntitle: NodeJS\nsort: \n--\x3e \n\n## NodeJS\n\n> `node.js`是基于chrome v8引擎的JS运行环境\n>\n> [包管理器安装](https://nodejs.org/zh-cn/download/package-manager/)\n\n```bash\n# Using Ubuntu\ncurl -fsSL https://deb.nodesource.com/setup_lts.x | sudo -E bash -\nsudo apt-get install -y nodejs\n\n# Using Debian, as root\ncurl -fsSL https://deb.nodesource.com/setup_lts.x | bash -\napt-get install -y nodejs\n```\n\n### Npm\n\n> [npmjs](https://www.npmjs.com/)\n\n```powershell\n# 安装\ncurl -L https://npmjs.org/install.sh |\n\n\nnode\t# 进入JS运行环境\nnpm init\nnpm install [-g]\t# 全局安装\n\t-S\t--save-dev\t# 安装为开发依赖\n# 换源\nnpm config set registry https://registry.npm.taobao.org\n# 发布包时换回原来的源\nnpm config set registry https://registry.npmjs.org\n# 发布插件\nnpm adduser | npm publish\n# 删除\nnpm unpublish --force\n```\n\n  ### Yarn\n\n  > `npm i yarn -g`\n  >\n  > 弥补了npm的一些缺陷\n  >\n  > [中文文档](https://yarn.bootcss.com/)\n\n  ```powershell\nnpm i yarn@1.22.0 -g \t# 安装特定版本\nnpm upgrade yarn -g\t\t# 更新\n  \nyarn config set registry https://registry.npm.taobao.org\n  \nyarn -v\n# 初始化项目\nyarn init\nyarn install\nyarn add/remove # 添加依赖包\nyarn global add\t# 全局安装\nyarn publish\nyarn run\n  ```\n\n  > 搭建环境\n\n  ```powershell\nyarn init\nyarn add xx --save\t# 添加新插件\nyarn install\t\t# 拉取旧插件\n\nyarn login\t\t\t# 登录\nyarn logout\t\t\t# 登出\n  ```\n\n  > 编辑Package\n\n  ```json\n"scripts": {\n    "ver": "npm -v"\n},\n  ```\n\n## Nvm\n\n> nodejs版本管理工具\n\n```bash\nnvm ls-remote\nnvm install vxx.xx.x\n```\n'}}]);